from machine import ADC
import time
from umqtt.simple import MQTTClient

# Initialize temperature sensor (ADC0 for ESP32-Pico)
adc = ADC(0)

# Configure MQTT broker
BROKER_IP = 'your_broker_ip'
CLIENT_ID = 'esp32_temp_sensor'
TEMP_TOPIC = b'sensors/temp'

def connect():
    print('Connecting to MQTT broker...')
    try:
        client = MQTTClient(CLIENT_ID, BROKER_IP)
        client.connect()
        return client
    except Exception as e:
        print('Error connecting to the broker:', str(e))
        return None

def measure_temp():
    adc.width(ADC.WIDTH_12BIT)
    temp = adc.read()
    # The temperature sensor returns a value proportional to the current temperature in Kelvin, 
    # so we convert it into Celsius by subtracting 273.15 from it
    return temp - 273.15

def main():
    client = connect()
    if not client:
        print('Failed to connect to the broker. Aborting...')
        return
    
    while True:
        temperature = measure_temp()
        print(f'Publishing temperature reading: {temperature} Celsius...')
        # Publish a string representation of the temperature measurement
        client.publish(TEMP_TOPIC, str(temperature))
        time.sleep(1)  # sleep for one second between each reading

main()